#include<bits/stdc++.h>
using namespace std;
int a[200010];
int sum[2][200010];
int n,q;
int lowbit(int x)
{
    return x&-x;
}
void update(int id,int x,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        sum[id][i]^=v;
    }
}
int query(int id,int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans^=sum[id][i];
    }
    return ans;
}
int main()
{
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        update(i%2,i,a[i]);
    }
    while(q--)
    {
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
        {
            update(x%2,x,(a[x]^y));
            a[x]=y;
        }
        else
        {
            int len=y-x+1;
            if(len%2==0)
            {
                printf("0\n");
                continue;
            }
            printf("%d\n",(query(x%2,y)^query(x%2,x-1)));
        }
    }
    return 0;
}
